from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'


DATA_DIR = 'data'

# Helper functions for data loading and saving

def load_properties():
    properties = []
    path = os.path.join(DATA_DIR, 'properties.txt')
    if not os.path.exists(path):
        return properties
    try:
        with open(path, encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 11:
                    continue
                property = {
                    'property_id': int(parts[0]),
                    'address': parts[1],
                    'location': parts[2],
                    'price': int(parts[3]),
                    'property_type': parts[4],
                    'bedrooms': int(parts[5]),
                    'bathrooms': float(parts[6]),
                    'square_feet': int(parts[7]),
                    'description': parts[8],
                    'agent_id': int(parts[9]),
                    'status': parts[10]
                }
                properties.append(property)
    except Exception:
        # Fail silently, return what loaded
        pass
    return properties


def load_locations():
    locations = []
    path = os.path.join(DATA_DIR, 'locations.txt')
    if not os.path.exists(path):
        return locations
    try:
        with open(path, encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 6:
                    continue
                location = {
                    'location_id': int(parts[0]),
                    'location_name': parts[1],
                    'region': parts[2],
                    'average_price': int(parts[3]),
                    'property_count': int(parts[4]),
                    'description': parts[5]
                }
                locations.append(location)
    except Exception:
        pass
    return locations


def load_inquiries():
    inquiries = []
    path = os.path.join(DATA_DIR, 'inquiries.txt')
    if not os.path.exists(path):
        return inquiries
    try:
        with open(path, encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 8:
                    continue
                inquiry = {
                    'inquiry_id': int(parts[0]),
                    'property_id': int(parts[1]),
                    'customer_name': parts[2],
                    'customer_email': parts[3],
                    'customer_phone': parts[4],
                    'message': parts[5],
                    'inquiry_date': parts[6],
                    'status': parts[7]
                }
                inquiries.append(inquiry)
    except Exception:
        pass
    return inquiries


def save_inquiries(inquiries):
    path = os.path.join(DATA_DIR, 'inquiries.txt')
    try:
        with open(path, 'w', encoding='utf-8') as f:
            for i in inquiries:
                line = f"{i['inquiry_id']}|{i['property_id']}|{i['customer_name']}|{i['customer_email']}|{i['customer_phone']}|{i['message']}|{i['inquiry_date']}|{i['status']}\n"
                f.write(line)
    except Exception:
        pass


def load_favorites():
    favorites = []
    path = os.path.join(DATA_DIR, 'favorites.txt')
    if not os.path.exists(path):
        return favorites
    try:
        with open(path, encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 3:
                    continue
                favorite = {
                    'favorite_id': int(parts[0]),
                    'property_id': int(parts[1]),
                    'added_date': parts[2]
                }
                favorites.append(favorite)
    except Exception:
        pass
    return favorites


def save_favorites(favorites):
    path = os.path.join(DATA_DIR, 'favorites.txt')
    try:
        with open(path, 'w', encoding='utf-8') as f:
            for fav in favorites:
                line = f"{fav['favorite_id']}|{fav['property_id']}|{fav['added_date']}\n"
                f.write(line)
    except Exception:
        pass


def load_agents():
    agents = []
    path = os.path.join(DATA_DIR, 'agents.txt')
    if not os.path.exists(path):
        return agents
    try:
        with open(path, encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 6:
                    continue
                agent = {
                    'agent_id': int(parts[0]),
                    'agent_name': parts[1],
                    'specialization': parts[2],
                    'email': parts[3],
                    'phone': parts[4],
                    'properties_sold': int(parts[5])
                }
                agents.append(agent)
    except Exception:
        pass
    return agents


# Route implementations

@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    # Load all properties
    properties = load_properties()
    # Featured properties: filter by status Available and pick top N (e.g. sort by price desc and take 5)
    featured_properties = [p for p in properties if p['status'] == 'Available']
    # Sort descending by price
    featured_properties.sort(key=lambda x: x['price'], reverse=True)
    featured_properties = featured_properties[:5]

    # Recent listings: Sort by property_id descending (simulating recent)
    recent_listings = sorted(properties, key=lambda x: x['property_id'], reverse=True)[:5]

    return render_template('dashboard.html', featured_properties=featured_properties, recent_listings=recent_listings)


@app.route('/properties/search')
def property_search():
    properties = load_properties()
    locations = list(set([p['location'] for p in properties]))
    locations.sort()

    # Read the search filter from query parameters
    location_filter = request.args.get('location', '')
    price_min = request.args.get('price_min')
    price_max = request.args.get('price_max')
    property_type = request.args.get('property_type')

    # Convert price_min and price_max to int or None
    try:
        price_min_val = int(price_min) if price_min is not None and price_min != '' else None
    except ValueError:
        price_min_val = None
    try:
        price_max_val = int(price_max) if price_max is not None and price_max != '' else None
    except ValueError:
        price_max_val = None

    # Filter properties
    filtered_properties = []
    for prop in properties:
        if location_filter and prop['location'] != location_filter:
            continue
        if property_type and property_type != '' and prop['property_type'] != property_type:
            continue
        if price_min_val is not None and prop['price'] < price_min_val:
            continue
        if price_max_val is not None and prop['price'] > price_max_val:
            continue
        if prop['status'] != 'Available':
            continue
        filtered_properties.append(prop)

    selected_filters = {
        'location': location_filter if location_filter != '' else None,
        'price_min': price_min_val,
        'price_max': price_max_val,
        'property_type': property_type if property_type != '' else None
    }

    return render_template('property_search.html', properties=filtered_properties, locations=locations, selected_filters=selected_filters)


@app.route('/properties/<int:property_id>')
def property_details(property_id):
    properties = load_properties()
    agents = load_agents()
    favorites = load_favorites()

    # Find property
    prop = next((p for p in properties if p['property_id'] == property_id), None)
    if prop is None:
        return "Property not found", 404

    # Find agent for this property
    agent = next((a for a in agents if a['agent_id'] == prop['agent_id']), None)

    # Check if favorite
    is_favorite = any(fav['property_id'] == property_id for fav in favorites)

    return render_template('property_details.html', property=prop, agent=agent, is_favorite=is_favorite)


@app.route('/inquiries/submit', methods=['GET'])
def inquiry_form():
    properties = load_properties()
    # Only properties that are available
    properties = [p for p in properties if p['status'] == 'Available']
    return render_template('inquiry_form.html', properties=properties)


@app.route('/inquiries/submit', methods=['POST'])
def submit_inquiry():
    # Validate required fields
    try:
        property_id = int(request.form.get('select-property', '').strip())
    except (ValueError, AttributeError):
        property_id = None
    customer_name = request.form.get('inquiry-name', '').strip()
    customer_email = request.form.get('inquiry-email', '').strip()
    customer_phone = request.form.get('inquiry-phone', '').strip()
    inquiry_message = request.form.get('inquiry-message', '').strip()

    errors = {}

    if property_id is None:
        errors['property_id'] = 'Property selection is required.'
    if not customer_name:
        errors['customer_name'] = 'Name is required.'
    if not customer_email or '@' not in customer_email:
        errors['customer_email'] = 'Valid email is required.'
    if not inquiry_message:
        errors['inquiry_message'] = 'Inquiry message is required.'

    properties = load_properties()
    properties_available = [p for p in properties if p['status'] == 'Available']

    # Check property_id is valid and available
    if property_id is not None and not any(p['property_id'] == property_id for p in properties_available):
        errors['property_id'] = 'Selected property is not available.'

    if errors:
        return render_template('inquiry_form.html', properties=properties_available, errors=errors,
                               form_data=request.form)

    inquiries = load_inquiries()
    new_id = 1
    if inquiries:
        new_id = max(i['inquiry_id'] for i in inquiries) + 1

    today_str = datetime.now().strftime('%Y-%m-%d')

    new_inquiry = {
        'inquiry_id': new_id,
        'property_id': property_id,
        'customer_name': customer_name,
        'customer_email': customer_email,
        'customer_phone': customer_phone or '',
        'message': inquiry_message,
        'inquiry_date': today_str,
        'status': 'Pending'
    }

    inquiries.append(new_inquiry)
    save_inquiries(inquiries)

    return redirect(url_for('my_inquiries'))


@app.route('/inquiries')
def my_inquiries():
    inquiries = load_inquiries()
    filter_status = request.args.get('status', 'All')

    if filter_status not in ['All', 'Pending', 'Contacted', 'Resolved']:
        filter_status = 'All'

