@app.route('/properties/search')
def property_search():
    properties = load_properties()
    locations = sorted(list(set(p['location'] for p in properties)))

    location_filter = request.args.get('location', '').strip()
    price_min_raw = request.args.get('price_min', '')
    price_max_raw = request.args.get('price_max', '')
    property_type_filter = request.args.get('property_type', '').strip()

    # Convert to int or None
    def safe_int(value):
        try:
            return int(value)
        except Exception:
            return None

    price_min = safe_int(price_min_raw) if price_min_raw else None
    price_max = safe_int(price_max_raw) if price_max_raw else None

    filtered_properties = []
    for p in properties:
        if p['status'] != 'Available':
            continue
        if location_filter and p['location'] != location_filter:
            continue
        if property_type_filter and p['property_type'] != property_type_filter:
            continue
        if price_min is not None and p['price'] < price_min:
            continue
        if price_max is not None and p['price'] > price_max:
            continue
        filtered_properties.append(p)

    selected_filters = {
        'location': location_filter if location_filter else None,
        'price_min': price_min,
        'price_max': price_max,
        'property_type': property_type_filter if property_type_filter else None
    }

    return render_template('property_search.html', properties=filtered_properties, locations=locations, selected_filters=selected_filters)


