@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist():
    username = get_current_username()

    waitlist = read_waitlist()

    # Check if user is already in active waitlist
    user_entry = None
    for entry in waitlist:
        if entry['username'] == username and entry['status'] == 'Active':
            user_entry = entry
            break

    if request.method == 'GET':
        user_position = None
        if user_entry:
            # Calculate user position (1-based) in active entries sorted by join_time
            active_entries = [e for e in waitlist if e['status'] == 'Active']
            active_entries.sort(key=lambda x: x['join_time'])
            for idx, e in enumerate(active_entries):
                if e['username'] == username:
                    user_position = idx + 1
                    break
        return render_template('waitlist.html', user_position=user_position)

    # POST: Add to waitlist
    party_size_str = request.form.get('party_size', '').strip()
    try:
        party_size = int(party_size_str)
        if party_size < 1:
            return render_template('waitlist.html', user_position=None, error_message='Party size must be at least 1.')
    except ValueError:
        return render_template('waitlist.html', user_position=None, error_message='Party size must be a valid number.')

    # If already in active waitlist, do not add duplicate
    if user_entry:
        # User already active in waitlist
        active_entries = [e for e in waitlist if e['status'] == 'Active']
        active_entries.sort(key=lambda x: x['join_time'])
        user_position = None
        for idx, e in enumerate(active_entries):
            if e['username'] == username:
                user_position = idx + 1
                break
        return render_template('waitlist.html', user_position=user_position, error_message='You are already in the waitlist.')

    # Add new waitlist entry
    new_waitlist_id = get_next_waitlist_id()
    join_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    new_entry = {
        'waitlist_id': new_waitlist_id,
        'username': username,
        'party_size': party_size,
        'join_time': join_time,
        'status': 'Active'
    }

    waitlist.append(new_entry)
    save_waitlist(waitlist)

    # Calculate new position
    active_entries = [e for e in waitlist if e['status'] == 'Active']
    active_entries.sort(key=lambda x: x['join_time'])
    user_position = None
    for idx, e in enumerate(active_entries):
        if e['username'] == username:
            user_position = idx + 1
            break

    return render_template('waitlist.html', user_position=user_position)


