                for u in users:
                    line = '|'.join([u['username'], u['email'], u['phone'], u['full_name']]) + '\n'
                    f.write(line)
        except Exception:
            return render_template('profile.html', username=username, email=user['email'], error_message='Error saving profile.')

        return render_template('profile.html', username=username, email=new_email, success_message='Profile updated successfully.')
