TRENDING_FILE = 'data/trending.txt'

# Helper functions for reading and writing data

def load_articles():
    articles = []
    if not os.path.exists(ARTICLES_FILE):
        return articles
    try:
        with open(ARTICLES_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 7:
                    continue
                try:
                    article = {
                        'article_id': int(parts[0]),
                        'title': parts[1],
                        'author': parts[2],
                        'category': parts[3],
                        'content': parts[4],
                        'date': parts[5],
                        'views': int(parts[6])
                    }
                    articles.append(article)
                except Exception:
                    continue
    except Exception:
        pass
    return articles

def load_categories():
    categories = []
    if not os.path.exists(CATEGORIES_FILE):
        return categories
    try:
        with open(CATEGORIES_FILE, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 3:
                    continue
                try:
                    category = {
                        'category_id': int(parts[0]),
                        'category_name': parts[1],
                        'description': parts[2]
                    }
                    categories.append(category)
                except Exception:
                    continue
    except Exception:
        pass
    return categories

def load_bookmarks():
    bookmarks = []
    if not os.path.exists(BOOKMARKS_FILE):
        return bookmarks
    try:
