        with open(COMMENTS_FILE, 'w', encoding='utf-8') as f:
            for comment in comments:
                line = f"{comment['comment_id']}|{comment['article_id']}|{comment['article_title']}|{comment['commenter_name']}|{comment['comment_text']}|{comment['comment_date']}"
                f.write(line + '\n')
