@app.route('/dashboard')
def dashboard():
    restaurants = load_restaurants()
    # Define featured_restaurants: Let's consider top 4 by rating desc
    sorted_by_rating = sorted(restaurants, key=lambda x: x['rating'], reverse=True)
    featured_restaurants = sorted_by_rating[:4] if len(sorted_by_rating) >=4 else sorted_by_rating

    # popular_cuisines: get unique cuisines sorted by count descending then alphabetically
    cuisine_counts = {}
    for r in restaurants:
        cuisine_counts[r['cuisine']] = cuisine_counts.get(r['cuisine'], 0) + 1
    popular_cuisines = sorted(cuisine_counts.items(), key=lambda x: (-x[1], x[0]))
    popular_cuisines = [c[0] for c in popular_cuisines]

    return render_template('dashboard.html', featured_restaurants=featured_restaurants, popular_cuisines=popular_cuisines)


