@app.route('/cart')
def view_cart():
    cart_items = load_cart()
    menus = load_menus()

    # Map item_id to menu item dict
    menu_dict = {m['item_id']: m for m in menus}

    # Build cart_items details list with extended info and calculate total amount
    detailed_cart_items = []
    total_amount = 0.0
    for ci in cart_items:
        item = menu_dict.get(ci['item_id'])
        if not item:
            continue
        amount = item['price'] * ci['quantity']
        total_amount += amount
        detailed_cart_items.append({
            'cart_id': ci['cart_id'],
            'item_id': ci['item_id'],
            'restaurant_id': ci['restaurant_id'],
            'quantity': ci['quantity'],
            'item_name': item['item_name'],
            'price': item['price'],
            'total_price': amount
        })

    return render_template('cart.html', cart_items=detailed_cart_items, total_amount=total_amount)


@app.route('/cart/update', methods=['POST'])
def update_cart():
    # We expect form data to update quantities or remove items
    # Form data contains keys like 'quantity_<cart_id>' for updating quantity
    # and 'remove_<cart_id>' if remove is requested

    cart_items = load_cart()
    # We'll build a dict from cart_id to cart item for quick access
    cart_dict = {ci['cart_id']: ci for ci in cart_items}

    updated = False
    for key in request.form:
        if key.startswith('quantity_'):
            try:
                cart_id = int(key.split('_')[1])
                if cart_id in cart_dict:
                    quantity_str = request.form[key]
                    quantity = int(quantity_str) if quantity_str.isdigit() else 0
                    if quantity < 0:
                        quantity = 0
                    if quantity == 0:
                        # remove this cart item later
                        cart_dict[cart_id]['quantity'] = 0
                    else:
                        cart_dict[cart_id]['quantity'] = quantity
                    updated = True
            except Exception:
                continue

        elif key.startswith('remove_'):
            try:
                cart_id = int(key.split('_')[1])
                if cart_id in cart_dict:
                    # mark quantity zero for removal
                    cart_dict[cart_id]['quantity'] = 0
                    updated = True
            except Exception:
                continue

    # Now rewrite cart.txt with only items quantity > 0
    new_cart_items = [ci for ci in cart_dict.values() if ci['quantity'] > 0]

    filepath = os.path.join(DATA_DIR, 'cart.txt')
    try:
        with open(filepath, 'w', encoding='utf-8') as f:
            for ci in new_cart_items:
                line = f"{ci['cart_id']}|{ci['item_id']}|{ci['restaurant_id']}|{ci['quantity']}|{ci['added_date']}\n"
                f.write(line)
    except Exception:
        # Could not write file but continue
        pass

    # Redirect back to /cart after update
    return redirect(url_for('view_cart'))


@app.route('/checkout', methods=['GET', 'POST'])
def checkout():
    if request.method == 'GET':
        return render_template('checkout.html')

    # POST: place order
    # Expected form fields: customer_name, delivery_address, phone_number, payment_method
    customer_name = request.form.get('customer_name', '').strip()
    delivery_address = request.form.get('delivery_address', '').strip()
    phone_number = request.form.get('phone_number', '').strip()
    payment_method = request.form.get('payment_method', '').strip()

    if not customer_name or not delivery_address or not phone_number or not payment_method:
        # Missing required fields, re-render with none order_confirmation
        return render_template('checkout.html', order_confirmation=None)

    # Load cart
    cart_items = load_cart()
    if not cart_items:
        # No items to order
        return render_template('checkout.html', order_confirmation=None)

    menus = load_menus()
    menu_dict = {m['item_id']: m for m in menus}

    total_amount = 0.0
    restaurant_ids = set()
    for ci in cart_items:
        item = menu_dict.get(ci['item_id'])
        if not item or item['availability'] != 1:
            continue
        total_amount += item['price'] * ci['quantity']
        restaurant_ids.add(ci['restaurant_id'])

    if len(restaurant_ids) != 1:
        # For simplicity, disallow multiple restaurant orders
        return render_template('checkout.html', order_confirmation=None)

    restaurant_id = restaurant_ids.pop()

    # Create new order_id as max existing order id + 1
    orders = load_orders()
    if orders:
        max_order_id = max(o['order_id'] for o in orders)
    else:
        max_order_id = 0
    new_order_id = max_order_id + 1

    order_date = datetime.now().strftime('%Y-%m-%d')
    new_order = f"{new_order_id}|{customer_name}|{restaurant_id}|{order_date}|{total_amount:.2f}|Pending|{delivery_address}|{phone_number}\n"

    orders_filepath = os.path.join(DATA_DIR, 'orders.txt')
    try:
        with open(orders_filepath, 'a', encoding='utf-8') as f:
            f.write(new_order)
    except Exception:
        # Fail silently
        return render_template('checkout.html', order_confirmation=None)

    # Append order_items
    order_items_data = []
    order_items_list = []
    order_items_filepath = os.path.join(DATA_DIR, 'order_items.txt')
    # Get next order_item_id as max existing + 1
    order_items = load_order_items()
    if order_items:
        max_order_item_id = max(oi['order_item_id'] for oi in order_items)
    else:
        max_order_item_id = 0

    current_order_item_id = max_order_item_id + 1
    menus_map = {m['item_id']: m for m in menus}

    for ci in cart_items:
        item = menus_map.get(ci['item_id'])
        if not item or item['availability'] != 1:
            continue
        price = item['price']
        quantity = ci['quantity']
        order_items_list.append({
            'order_item_id': current_order_item_id,
            'order_id': new_order_id,
            'item_id': ci['item_id'],
            'quantity': quantity,
            'price': price
        })
        line = f"{current_order_item_id}|{new_order_id}|{ci['item_id']}|{quantity}|{price:.2f}\n"
        order_items_data.append(line)
        current_order_item_id += 1

    try:
        with open(order_items_filepath, 'a', encoding='utf-8') as f:
            f.writelines(order_items_data)
    except Exception:
        # Fail silently
        return render_template('checkout.html', order_confirmation=None)

    # Clear cart after placing order
    cart_filepath = os.path.join(DATA_DIR, 'cart.txt')
    try:
        open(cart_filepath, 'w').close()
    except Exception:
        pass

    order_confirmation = {
        'order_id': new_order_id,
        'customer_name': customer_name,
        'restaurant_id': restaurant_id,
        'order_date': order_date,
        'total_amount': total_amount,
        'status': 'Pending',
        'delivery_address': delivery_address,
        'phone_number': phone_number
    }

    return render_template('checkout.html', order_confirmation=order_confirmation)


@app.route('/orders/active')
def active_orders():
    orders = load_orders()
    # Filter active orders where status is not Delivered or Cancelled
    active_orders = [o for o in orders if o['status'].lower() not in ['delivered', 'cancelled']]

    status_set = sorted(set(o['status'] for o in active_orders))
    status_options = status_set

    return render_template('active_orders.html', active_orders=active_orders, status_options=status_options)


@app.route('/orders/track/<int:order_id>')
def track_order(order_id):
    orders = load_orders()
    deliveries = load_deliveries()
    order_items = load_order_items()
    menus = load_menus()

    order = next((o for o in orders if o['order_id'] == order_id), None)
    if not order:
        abort(404)

    delivery_info = next((d for d in deliveries if d['order_id'] == order_id), None)
    if not delivery_info:
        # Provide empty dict if no delivery info
        delivery_info = {}

    order_items_list = [oi for oi in order_items if oi['order_id'] == order_id]

    # augment order items with name and price
    item_map = {m['item_id']: m for m in menus}
    detailed_items = []
    for oi in order_items_list:
        item = item_map.get(oi['item_id'])
        if item:
            detailed_items.append({
                'order_item_id': oi['order_item_id'],
                'item_id': oi['item_id'],
                'item_name': item['item_name'],
                'quantity': oi['quantity'],
                'price': oi['price']
            })

    return render_template('track_order.html', order=order, delivery_info=delivery_info, order_items=detailed_items)


@app.route('/reviews')
def reviews():
    reviews_data = load_reviews()
    rating_filter_options = sorted(set(r['rating'] for r in reviews_data))
    return render_template('reviews.html', reviews=reviews_data, rating_filter_options=rating_filter_options)


@app.route('/reviews/write', methods=['GET', 'POST'])
def write_review():
    submission_status = None
    restaurants = load_restaurants()

    if request.method == 'POST':
        # Fields: restaurant_id, customer_name, rating, review_text
        try:
            restaurant_id = int(request.form.get('restaurant_id', '0'))
        except Exception:
            restaurant_id = 0
        customer_name = request.form.get('customer_name', '').strip()

        try:
            rating = int(request.form.get('rating', '0'))
        except Exception:
            rating = 0

        review_text = request.form.get('review_text', '').strip()

        if restaurant_id <= 0 or not any(r['restaurant_id'] == restaurant_id for r in restaurants):
            submission_status = False
        elif not customer_name or not review_text or rating < 1 or rating > 5:
            submission_status = False
        else:
            # Append new review
            reviews = load_reviews()
            if reviews:
                max_review_id = max(rv['review_id'] for rv in reviews)
            else:
                max_review_id = 0
            new_review_id = max_review_id + 1
            review_date = datetime.now().strftime('%Y-%m-%d')

            review_line = f"{new_review_id}|{restaurant_id}|{customer_name}|{rating}|{review_text}|{review_date}\n"
            try:
                reviews_filepath = os.path.join(DATA_DIR, 'reviews.txt')
                with open(reviews_filepath, 'a', encoding='utf-8') as f:
                    f.write(review_line)
                submission_status = True
            except Exception:
                submission_status = False

    return render_template('write_review.html', submission_status=submission_status, restaurants=restaurants)


if __name__ == '__main__':
    app.run(debug=True, port=5000)

