@app.route('/reviews/write', methods=['GET', 'POST'])
def write_review():
    submission_status = None
    restaurants = load_restaurants()

    if request.method == 'POST':
        # Fields: restaurant_id, customer_name, rating, review_text
        try:
            restaurant_id = int(request.form.get('restaurant_id', '0'))
        except Exception:
            restaurant_id = 0
        customer_name = request.form.get('customer_name', '').strip()

        try:
            rating = int(request.form.get('rating', '0'))
        except Exception:
            rating = 0

        review_text = request.form.get('review_text', '').strip()

        if restaurant_id <= 0 or not any(r['restaurant_id'] == restaurant_id for r in restaurants):
            submission_status = False
        elif not customer_name or not review_text or rating < 1 or rating > 5:
            submission_status = False
        else:
            # Append new review
            reviews = load_reviews()
            if reviews:
                max_review_id = max(rv['review_id'] for rv in reviews)
            else:
                max_review_id = 0
            new_review_id = max_review_id + 1
            review_date = datetime.now().strftime('%Y-%m-%d')

            review_line = f"{new_review_id}|{restaurant_id}|{customer_name}|{rating}|{review_text}|{review_date}\n"
            try:
                reviews_filepath = os.path.join(DATA_DIR, 'reviews.txt')
                with open(reviews_filepath, 'a', encoding='utf-8') as f:
                    f.write(review_line)
                submission_status = True
            except Exception:
                submission_status = False

    return render_template('write_review.html', submission_status=submission_status, restaurants=restaurants)


