    sorted_by_rating = sorted(restaurants, key=lambda x: x['rating'], reverse=True)
    featured_restaurants = sorted_by_rating[:4] if len(sorted_by_rating) >= 4 else sorted_by_rating

    # popular_cuisines: unique cuisines ordered by count desc then name
    cuisine_counts = {}
    for r in restaurants:
